        MOD = 10**9 + 7
        n = len(nums)
        orAll = 0
        for x in nums:
            orAll |= x
        count = 0
        for mask in range(1 << n):
            rem = 0
            for i in range(n):
                if not (mask >> i) & 1:
                    rem |= nums[i]
            if rem < orAll:
                count += 1
        return count % MOD

