class Solution:
    def countEffective(self, nums: List[int]) -> int:
        MOD = 10**9 + 7
        n = len(nums)
        orAll = 0
        for x in nums:
            orAll |= x
        if orAll == 0:
            return 0
        bits = [b for b in range(20) if (orAll >> b) & 1]
        bcount = len(bits)
        bitpos = {bit: i for i, bit in enumerate(bits)}
        size = 1 << bcount
        cnt = [0] * size
        for x in nums:
            v = x & orAll
            m = 0
            for bit in bits:
                if (v >> bit) & 1:
                    m |= (1 << bitpos[bit])
            cnt[m] += 1
        g = cnt[:]
        for j in range(bcount):
            bitmask = 1 << j
            for mask in range(size):
                if mask & bitmask:
                    g[mask] += g[mask ^ bitmask]
        full = size - 1
        total_full_or = 0
        for mask in range(size):
            t = full ^ mask
            sign = -1 if (bin(t).count('1') % 2) else 1
            total_full_or = (total_full_or + sign * pow(2, g[mask], MOD)) % MOD
        total_subsets = pow(2, n, MOD)
        return (total_subsets - total_full_or) % MOD

