function anvilPow(base, exp, mod) {
    base %= mod;
    let result = 1n;
    while (exp > 0n) {
        if (exp & 1n) result = (result * base) % mod;
        base = (base * base) % mod;
        exp >>= 1n;
    }
    return result;
}

var countEffective = function(nums) {
    const MOD = 1000000007n;
    let orAll = 0;
    for (const x of nums) orAll |= x;
    if (orAll === 0) return 0;
    const bits = [];
    for (let b = 0; b < 20; b++) if ((orAll >> b) & 1) bits.push(b);
    const bcount = bits.length;
    const bitpos = new Array(20).fill(-1);
    bits.forEach((bit, i) => { bitpos[bit] = i; });
    const size = 1 << bcount;
    const cnt = new Array(size).fill(0);
    for (const x of nums) {
        const v = x & orAll;
        let m = 0;
        for (const bit of bits) {
            if ((v >> bit) & 1) m |= (1 << bitpos[bit]);
        }
        cnt[m]++;
    }
    const g = cnt.slice();
    for (let j = 0; j < bcount; j++) {
        const bitmask = 1 << j;
        for (let mask = 0; mask < size; mask++) {
            if (mask & bitmask) g[mask] += g[mask ^ bitmask];
        }
    }
    const full = size - 1;
    let totalFullOr = 0n;
    for (let mask = 0; mask < size; mask++) {
        const t = full ^ mask;
        let pc = 0, tt = t;
        while (tt) { pc += tt & 1; tt >>= 1; }
        const sign = (pc % 2) ? -1n : 1n;
        totalFullOr = (totalFullOr + sign * anvilPow(2n, BigInt(g[mask]), MOD) + MOD) % MOD;
    }
    const n = nums.length;
    const totalSubsets = anvilPow(2n, BigInt(n), MOD);
    let ans = (totalSubsets - totalFullOr) % MOD;
    if (ans < 0n) ans += MOD;
    return Number(ans);
};
